// Group grocery tasks by section (store)
const sectionMap = {
  '68rmW3xf7G3qppcq': 'Vons',
  '68rpFq5F3Ph6cw8q': 'Amazon',
  '68vQM5WwjqhCJpmH': 'Costco',
  '68rpVFvmHVGMg9vq': 'Target'
};

const stores = {
  'Vons': [],
  'Amazon': [],
  'Costco': [],
  'Target': [],
  'Other': []
};

const items = $input.all();
let totalItems = 0;

for (const item of items) {
  const sectionId = item.json.sectionId || item.json.section_id || '';
  const content = item.json.content || '';
  const storeName = sectionMap[sectionId] || 'Other';
  stores[storeName].push(content);
  totalItems++;
}

// Build HTML shopping list
const today = new Date();
const dateStr = today.toLocaleDateString('en-US', { month: 'long', day: 'numeric' });

let html = `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;">`;
html += `<h1 style="color:#1a1a1a;border-bottom:2px solid #e5e5e5;padding-bottom:8px;">Shopping List — ${dateStr}</h1>`;

const storeColors = {
  'Vons': '#DC2626',
  'Costco': '#2563EB',
  'Amazon': '#F59E0B',
  'Target': '#DC2626',
  'Other': '#6B7280'
};

for (const [store, taskList] of Object.entries(stores)) {
  if (taskList.length === 0) continue;
  const color = storeColors[store] || '#6B7280';
  html += `<h2 style="color:${color};margin-top:20px;margin-bottom:8px;">${store.toUpperCase()} (${taskList.length} item${taskList.length !== 1 ? 's' : ''})</h2>`;
  html += `<ul style="list-style:none;padding-left:8px;">`;
  for (const task of taskList) {
    html += `<li style="padding:4px 0;font-size:15px;">&#9723; ${task}</li>`;
  }
  html += `</ul>`;
}

html += `<hr style="margin-top:24px;border-color:#e5e5e5;"><p style="color:#6B7280;font-size:14px;"><strong>Total items: ${totalItems}</strong></p>`;
html += `</div>`;

return [{
  json: {
    subject: `Shopping List — ${dateStr}`,
    htmlBody: html,
    totalItems
  }
}];
